class DBMDBLockHistoryCleanup extends RunBaseBatch implements BatchRetryable
{
    DialogField   dialogHistoryLimit;

    int historyLimit;
    #define.CurrentVersion(2)
    #localmacro.CurrentList
        historyLimit
    #endmacro

    #OCCRetryCount

}

Method.Source:
public final boolean isRetryable()
{
    return true;
}

private void deleteHistory()
{
    DBMDbLockHistory dbLockHistory;
    dbLockHistory.queryTimeout(1, true);
    dbLockHistory.skipAosValidation(true);
    dbLockHistory.skipDataMethods(true);
    dbLockHistory.skipEvents(true);
    dbLockHistory.skipDatabaseLog(true);
    dbLockHistory.skipDeleteActions(true);
    utcdatetime keepFrom = DateTimeUtil::addDays(DateTimeUtil::getSystemDateTime(), -historyLimit);
    delete_from dbLockHistory
    where dbLockHistory.CreatedDateTime < keepFrom;
}

public Object dialog()
{
    DialogRunbase dlg = super();

    dialogHistoryLimit = dlg.addField(extendedtypestr(Days), "@SYS69354", "@DBMLockMonitor:NumberOfDaysToKeep");
    dialogHistoryLimit.value(historyLimit);


    return dlg;
}

public boolean getFromDialog()
{
    historyLimit = dialogHistoryLimit.value();

    if(historyLimit < 0)
    {
        error("@SYS98150");
        return false;
    }

    return super();

}

public void run()
{
    #OCCRetryCount
    try
    {
        ttsbegin;
        this.deleteHistory();
        ttscommit;
    }
    #StandardRetryCatchBlock

}

public boolean unpack(container _packedClass)
{
    Integer     version     = RunBase::getVersion(_packedClass);

    switch (version)
    {
        case #CurrentVersion:
            [version, #CurrentList] = _packedClass;
            break;

        default :
            return false;
    }

    return true;
}

client server static ClassDescription description()
{
    return "@DBMLockMonitor:CleanupDBLockHistory";
}

static void main(Args _args)
{
    DBMDBLockHistoryCleanup historyCleanup;

    historyCleanup = new DBMDBLockHistoryCleanup();
    historyCleanup.batchInfo().parmBatchExecute(NoYes::Yes);

    if (historyCleanup.prompt())
    {
        historyCleanup.runOperation();
    }

}
